import logo from "./logo.svg";
import "./App.css";
import { render } from "@testing-library/react";
import { useState } from "react";

function App() {
  return (
    <div className="App">
      <header>Weight Calc</header>
      <WeightInputForm />
    </div>
  );
}
function WeightInputForm() {
  // Array to store the weights from the weight inputs
  const [weightInputs, setWeightInputs] = useState([]);
  // Stores the result of calculating the weight layout
  const [weightLayout, setWeightLayout] = useState("");
  // Stores the desired weight
  const [weightTarget, setWeightTarget] = useState(0);
  const [barWeight, setBarWeight] = useState(0);
  // Comparator to sort the weightInputs (A, B) array by weight (B - A for descending order)
  const sortWeightInputs = (inputA, inputB) => {
    return Number(inputB.weight) - Number(inputA.weight);
  };
  // Handles changes in the weight inputs
  const handleFormChange = (index, event) => {
    let data = [...weightInputs];
    data[index][event.target.name] = event.target.value;
    setWeightInputs(data);
  };
  // Adds a weight input field
  const addWeightInput = () => {
    let newWeightInput = { weight: "", amount: "" };
    setWeightInputs([...weightInputs, newWeightInput]);
  };
  // Removes the index-th weight input field
  const removeWeightInput = (index) => {
    let data = [...weightInputs];
    data.splice(index, 1);
    setWeightInputs(data);
  };
  // Calculates the weight layout for given weights and target
  // Runs after clicking the "Calculate" button
  const calculateWeights = (e) => {
    e.preventDefault();
    const weights = weightInputs.map((input) => {
      return { weight: input.weight * 100, amount: input.amount };
    });
    weights.sort(sortWeightInputs);
    if (weightTarget - barWeight === 0) {
      setWeightLayout("Just the bar");
      return;
    }
    const toRet = weightCalc((weightTarget - barWeight) * 100, weights);
    let toLayout;
    if (toRet != null) {
      toLayout = "Use ";
      for (const weight of toRet.keys()) {
        toLayout += `${toRet.get(weight)} ${weight / 100}s, `;
      }
      toLayout = toLayout.slice(0, toLayout.length - 2);
    } else toLayout = "Unable to make desired weight";
    setWeightLayout(toLayout);
  };
  // Implements the calculation of the weights
  const weightCalc = (target, weights) => {
    const combos = new Map();
    let sum = 0;
    for (let i = 0; i < weights.length; i++) {
      let diff = target - sum;
      let numWeights = Math.floor(diff / weights[i]["weight"] / 2) * 2;
      if (numWeights === 0) continue;
      let added = Math.min(
        numWeights,
        Math.floor(weights[i]["amount"] / 2) * 2
      );
      sum += added * weights[i]["weight"];
      combos.set(weights[i].weight, added);
      weights[i].amount -= added;
      if (sum === target) return combos;
    }
    return null;
  };
  return (
    <div className="weight-calculator">
      <p>{weightLayout}</p>
      <form className="weight-input-form">
        <div className="target-weight">
          <label htmlFor="target-weight-input">Target Weight:</label>
          <input
            type="tel"
            value={weightTarget}
            id="target-weight-input"
            onChange={(event) => {
              setWeightTarget(event.target.value);
            }}
          ></input>
        </div>
        <div className="bar-info">
          <label htmlFor="bar-weight">Bar Weight:</label>
          <input
            type="tel"
            id="bar-weight"
            value={barWeight}
            onChange={(event) => {
              setBarWeight(event.target.value);
            }}
          />
          <label htmlFor="bar-type">Bar Type:</label>
          <select id="bar-type">
            <option>Barbell</option>
            <option>Dumbbell</option>
          </select>
        </div>
        <div className="weight-input-fields">
          {weightInputs.map((input, index) => {
            return (
              <div key={index} className="weight-input">
                <label htmlFor={`weight-input${index}`}>Weight:</label>
                <input
                  type="tel"
                  id={`weight-input${index}`}
                  name="weight"
                  value={input.weight}
                  onChange={(event) => handleFormChange(index, event)}
                />
                <label htmlFor={`weight-amount${index}`}>Amount:</label>
                <input
                  type="tel"
                  name="amount"
                  id={`weight-amount${index}`}
                  value={input.amount}
                  onChange={(event) => handleFormChange(index, event)}
                />
                <button type="button" onClick={() => removeWeightInput(index)}>
                  Remove
                </button>
              </div>
            );
          })}
          <button type="button" onClick={addWeightInput}>
            Add weight
          </button>
        </div>
        <button type="button" onClick={calculateWeights}>
          Calculate
        </button>
      </form>
    </div>
  );
}

export default App;
